1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_FACTOR = 1.1;
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	const itemPremium = (item: Item): number =>
14	  BASE_PREMIUM[item.type] * FIRST_INSURANCE_FACTOR;
15	
16	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
17	
18	const priceQuote = (step: QuoteStep): { premium: number } => ({
19	  premium: ceilWithEpsilon(step.items.reduce((sum, item) => sum + itemPremium(item), 0) + PROCESSING_FEE),
20	});
21	
22	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
23	  results: scenario.steps.map(priceQuote),
24	});
25

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote: base premiums
6	  it("empty item list yields a premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it("a single sword (plain, newcomer first contract) yields a premium of 115 G (100 base + 10 first + 5 fee)", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result.results[0]).toEqual({ premium: 115 });
24	  });
25	  it("a single amulet (plain, newcomer first contract) yields a premium of 71 G (60 base + 6 first + 5 fee)", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [
29	        {
30	          op: "quote",
31	          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
32	        },
33	      ],
34	    });
35	    expect(result.results[0]).toEqual({ premium: 71 });
36	  });
37	
38	  // Quote: components and blocks
39	  it.todo("2 runes (plain, newcomer first contract) yields a premium of 60 G (50 base + 5 first + 5 fee)");
40	  it.todo("3 runes form a block: base premium 60 G total");
41	  it.todo("3 runes + 3 moonstones form two blocks: base premium 120 G total");
42	
43	  // Quote: modifiers
44	  it.todo("a cursed sword applies +50% surcharge on the cursed item only");
45	  it.todo("high enchantment (level >= 5) sword applies +30% surcharge");
46	  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy total");
47	  it.todo("follow-up contract receives 15% discount on policy total");
48	  it.todo("policy with cursed sword and plain amulet: cursed surcharge applies only to cursed item");
49	
50	  // Quote: rounding and integration
51	  it.todo("premium is rounded up in MHPCO's favor");
52	  it.todo("newcomer with a cursed sword (steel, enchantment 3) yields premium of 165 G");
53	  it.todo("long-standing customer's second contract with cursed sword enchantment 7 yields 160 G");
54	
55	  // Claim: basic
56	  it.todo("plain sword damage 500 G yields payout 400 G (full reimbursement minus 100 deductible)");
57	  it.todo("rune damage 200 G yields payout 100 G");
58	  it.todo("enchantment >= 8 reimburses at 50% then deductible");
59	  it.todo("dragon-material item is fully reimbursed before deductible");
60	  it.todo("dragon-material + enchantment >= 8: 50% rule wins, then deductible");
61	  it.todo("dragon attack damaging sword and amulet: deductible applies per damage entry");
62	
63	  // Claim: cap
64	  it.todo("payout is capped at twice the insurance sum across multiple claims");
65	  it.todo("cap is based on unmodified insurance value, not modified premium");
66	
67	  // Edge cases
68	  it.todo("quote with unknown item type causes the CLI to exit with non-zero status");
69	  it.todo("claim referencing damage to item not in policy causes non-zero exit");
70	  it.todo("claim with negative damage amount causes non-zero exit");
71	  it.todo("more damage entries of a type than items insured causes non-zero exit");
72	});
