const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);

const sumItemPremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemPremium(item), 0);

const priceQuote = (step: QuoteStep): { premium: number } => ({
  premium: ceilWithEpsilon(sumItemPremiums(step.items) + PROCESSING_FEE),
});
